{"version": 2, "columns": {"apollocompany": {"name": "apollo_company", "tool_id": "apollo_company_search", "source": "updated", "operation": "apollo_company_search", "payload_template": {"q_organization_name": "{{Company}}", "per_page": 3, "page": 1}}, "companyprofile": {"name": "company_profile", "tool_id": "run_javascript", "source": "updated", "operation": "run_javascript", "payload_template": {"code": "const q = (row["Company"] || "").trim().toLowerCase();
const d = row["apollo_company"]?.data || {};
const accts = d.accounts || [];
const orgs = d.organizations || [];
const pool = accts.length > 0 ? accts : orgs;
const a = pool.find(x => {
  const name = (x?.name || "").trim().toLowerCase();
  return name === q || name.includes(q) || q.includes(name);
}) || pool[0] || null;
if (!a) return null;
return {
  company_name: a.name || null,
  company_domain: a.primary_domain || a.domain || a.website_url?.replace(/^https?:\/\/(www\.)?/, '').replace(/\/$/, '') || null,
  company_linkedin: a.linkedin_url || null,
  employee_count: a.estimated_num_employees || null
};
"}}, "dropleadscontacts": {"name": "dropleads_contacts", "tool_id": "dropleads_search_people", "source": "updated", "operation": "dropleads_search_people", "payload_template": {"filters": {"jobTitlesSimilar": ["Sales", "Growth", "Revenue", "Marketing", "GTM", "Founder", "CEO"], "seniority": ["C-Level", "VP", "Director", "Owner", "Founder"], "companyDomains": ["{{Domain}}"]}, "pagination": {"page": 1, "limit": 10}}}, "apollocontacts": {"name": "apollo_contacts", "tool_id": "apollo_search_people", "source": "updated", "operation": "apollo_search_people", "payload_template": {"q_organization_domains_list": ["{{Domain}}"], "person_seniorities": ["founder", "c_suite", "vp", "head", "director"], "person_titles": ["Sales", "Growth", "Revenue", "Marketing", "GTM", "CEO", "Founder"], "include_similar_titles": true, "per_page": 5, "page": 1}}, "allcandidates": {"name": "all_candidates", "tool_id": "run_javascript", "source": "added", "operation": "run_javascript", "payload_template": {"code": "const dl = row["dropleads_contacts"]?.data?.leads || [];
const ap = row["apollo_contacts"]?.data?.people || [];

// Merge all candidates
const candidates = [];
for (const l of dl) {
  candidates.push({
    full_name: l.fullName || "",
    title: l.title || "",
    linkedin_url: l.linkedinUrl || "",
    source: "dropleads"
  });
}
for (const p of ap) {
  const ln = p.last_name_obfuscated || "";
  candidates.push({
    full_name: (p.first_name || "") + " " + ln,
    title: p.title || "",
    linkedin_url: p.linkedin_url || "",
    apollo_id: p.id || "",
    source: "apollo"
  });
}

if (candidates.length === 0) return null;
return candidates;
"}}, "bestcontact": {"name": "best_contact", "tool_id": "call_ai", "source": "updated", "operation": "call_ai", "payload_template": {"prompt": "You are picking the single best person to sell outbound GTM infrastructure services to (signal-based outbound, Clay-powered pipeline systems, automated prospecting).

Company: {{Company}} ({{Domain}})
Funding: {{Funding}}
Why they fit: {{Why_Fit}}

Candidates:
{{all_candidates}}

Pick ONE person. Prefer: VP/Head/Director of Sales, Growth, RevOps, Marketing, or GTM Ops. At small companies (<50 employees), Founders and CEOs who own go-to-market are great. Skip CTOs and pure engineering roles.

Return strict JSON.", "model": "haiku", "agent": "claude", "json_mode": {"type": "object", "properties": {"full_name": {"type": "string"}, "first_name": {"type": "string"}, "last_name": {"type": "string"}, "title": {"type": "string"}, "linkedin_url": {"type": "string"}, "why_this_person": {"type": "string"}}, "required": ["full_name", "first_name", "last_name", "title", "why_this_person"], "additionalProperties": false}}}, "contactinfo": {"name": "contact_info", "tool_id": "run_javascript", "source": "added", "operation": "run_javascript", "payload_template": {"code": "const bc = row["best_contact"]?.extracted_json || row["best_contact"]?.output || {};
return {
  first_name: bc.first_name || "",
  last_name: bc.last_name || "",
  full_name: bc.full_name || "",
  title: bc.title || "",
  linkedin_url: bc.linkedin_url || "",
  why_fit: bc.why_this_person || ""
};
"}}, "dropleadsemail": {"name": "dropleads_email", "tool_id": "dropleads_email_finder", "source": "updated", "operation": "dropleads_email_finder", "payload_template": {"first_name": "{{contact_info.first_name}}", "last_name": "{{contact_info.last_name}}", "company_name": "{{Company}}"}, "waterfall": {"group_id": "wf_email", "step_index": 0, "enabled": true, "display_name": "email", "type": "email", "result_getters": ["data.email", "email", "data.0.email", "data.emails.0.value", "emails.0.value"]}}, "hunteremail": {"name": "hunter_email", "tool_id": "hunter_email_finder", "source": "updated", "operation": "hunter_email_finder", "payload_template": {"first_name": "{{contact_info.first_name}}", "last_name": "{{contact_info.last_name}}", "domain": "{{Domain}}"}, "waterfall": {"group_id": "wf_email", "step_index": 1, "enabled": true, "display_name": "email", "type": "email", "result_getters": ["data.email", "email", "data.0.email", "data.emails.0.value", "emails.0.value"]}}, "apolloemail": {"name": "apollo_email", "tool_id": "apollo_people_match", "source": "updated", "operation": "apollo_people_match", "payload_template": {"first_name": "{{contact_info.first_name}}", "last_name": "{{contact_info.last_name}}", "organization_name": "{{Company}}", "domain": "{{Domain}}"}, "waterfall": {"group_id": "wf_email", "step_index": 2, "enabled": true, "display_name": "email", "type": "email", "result_getters": ["data.email", "email", "data.0.email", "data.emails.0.value", "emails.0.value"]}}, "leadmagicemail": {"name": "leadmagic_email", "tool_id": "leadmagic_email_finder", "source": "updated", "operation": "leadmagic_email_finder", "payload_template": {"first_name": "{{contact_info.first_name}}", "last_name": "{{contact_info.last_name}}", "domain": "{{Domain}}"}, "waterfall": {"group_id": "wf_email", "step_index": 3, "enabled": true, "display_name": "email", "type": "email", "result_getters": ["data.email", "email", "data.0.email", "data.emails.0.value", "emails.0.value"]}}, "nativeemail": {"name": "native_email", "tool_id": "deepline_native_enrich_contact", "source": "updated", "operation": "enrich_contact", "payload_template": {"first_name": "{{contact_info.first_name}}", "last_name": "{{contact_info.last_name}}", "domain": "{{Domain}}"}, "waterfall": {"group_id": "wf_email", "step_index": 4, "enabled": true, "display_name": "email", "type": "email", "result_getters": ["data.email", "email", "data.0.email", "data.emails.0.value", "emails.0.value"]}}, "email": {"name": "email", "tool_id": "run_javascript", "source": "updated", "operation": "run_javascript", "payload_template": {"code": "return row["email"]||null;"}}, "outreachmessage": {"name": "outreach_message", "tool_id": "call_ai", "source": "updated", "operation": "call_ai", "payload_template": {"prompt": "You are writing a cold outreach email from Lucas at Thresh (runthresh.com) to a prospect.

Lucas's voice: Direct, warm, gets to the point fast. 20-40 words max for the email body. Friendly without being chatty. Never pushy. Offers value upfront. Signs off with "Cheers, Lucas".

Thresh: Signal-based outbound for niche B2B companies. Lucas spent 4+ years as an SDR/AE and 9 months at Clay Labs. He builds outbound systems that turn signals into pipeline — enrichment, qualification, personalized messaging, all automated. He hands the keys to your team when done.

Prospect:
- Name: {{contact_info.full_name}}
- Title: {{contact_info.title}}
- Company: {{Company}} ({{Domain}})
- Funding: {{Funding}}
- Why they fit: {{Why_Fit}}
- Why this person: {{contact_info.why_fit}}

Write ONE cold email. Subject line should be casual and specific to them (max 5 words, lowercase). Body should be 2-3 sentences max. Reference something specific about their company or situation. End with a low-friction CTA. Sign off: Cheers, Lucas.

Return strict JSON.", "model": "haiku", "agent": "claude", "json_mode": {"type": "object", "properties": {"subject": {"type": "string"}, "body": {"type": "string"}, "personalization_hook": {"type": "string"}}, "required": ["subject", "body", "personalization_hook"], "additionalProperties": false}}}}}

